var e=[{id:`L2_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`해치워도 해치워도 계속 몰려드는군.`,JPN:`倒しても倒してもキリがないな。`,ENG:`They wouldn't stop coming.`,TWN:`不管怎麼清理，還是不斷有敵人湧上來呢。`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}},sfx:`FX_CUTSCEN_FOOTSTEP_WALK_02`},{id:`L3_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`이렇게 불리한 장소에선 싸움을 피하는 게 야전 교범 제 1수칙인데 말이야.`,JPN:`こんな不利な場所では戦闘回避が野戦教範の第1項なのだが。`,ENG:`The first rule of thumb in field combat is to avoid fighting in unfavorable locations like this.`,TWN:`明明野戰法則的第一條，就是要避免在這種不利的地方戰鬥。`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`카일에게 전투 평가 C를 맞아도 할 말이 없겠어.`,JPN:`これはカイルに戦闘評価Cをつけられても文句を言えないな。`,ENG:`Kyle would have given me C for my combat performance if he was here.`,TWN:`看來從凱爾那裡拿到戰鬥評價 C，我也無話可說了。`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`과연...... 이런 곳에 있었나?`,JPN:`なるほど……こんなところにあったのか。`,ENG:`Ah, there you are.`,TWN:`果然……在這種地方嗎？`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`전술 컴퓨터! 목표인 정보부 특무함을 육안으로 확인했다.`,JPN:`戦術コンピューター！　目標の情報局特務艦を肉眼で確認した。`,ENG:`Tactical computer, our target, the auxiliary ship of the Intelligence Agency, is within sight.`,TWN:`戰術電腦！用肉眼確認了是為目標的情報部特務艦。`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`지금부터 특무함 안으로 진입하겠다.`,JPN:`これより特務艦の中に進入する。`,ENG:`I'm entering the ship now.`,TWN:`現在準備進入特務艦內部。`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`뉴 오하이오는 내가 지원을 요청할 때까지 스텔스 모드로 대기하도록!`,JPN:`ニューオハイオは私が支援を要請するまでステルスモードで待機せよ！`,ENG:`Have the New Ohio standing by in stealth mode until I need her support.`,TWN:`新俄亥俄在我要求支援之前，以隱形模式待機！`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`COMPUTER_VOICE_NULL_RED`,text:{KOREA:`명령 확인. 스탤스 모드로 전환합니다.`,JPN:`命令受付完了。ステルスモードに切り替えます。`,ENG:`Command confirmed. Switching to stealth mode...`,TWN:`確認命令。切換為隱形模式。`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}},sfx:`FX_CUTSCEN_SYS_START1`},{id:`L14_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`그런데 이상하군.`,JPN:`しかし、妙だな。`,ENG:`By the way, this is strange.`,TWN:`不過有些奇怪啊。`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`침식체들이 이렇게 많이 모여 있는데 함선은 지나치게 멀쩡해 보이는걸?`,JPN:`これだけの侵食体どもが群がっているのに、艦船は何ともないように見える。`,ENG:`The ship looks strangely unscathed, considering the number of C.O.s around it.`,TWN:`這裡聚集了這麼多侵蝕體，但艦船也太過完好無損了吧？`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`설마 내가 오길 기다리고 있었던 건가......?`,JPN:`まさか、私の到着を待っていたのか……？`,ENG:`Wait... Were they waiting for me?`,TWN:`難道是在等我的到來嗎？`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`아니, 그럴 리가 없지. 나도 나이가 먹으니 걱정만 많아졌나 보군.`,JPN:`いや、そんなはずはないか。私も年をとって心配性になったようだな。`,ENG:`What am I talking about? I'm getting paranoid in my old age.`,TWN:`不，不可能會有這種事。看來年紀大了，我也開始瞎操心了呢。`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`뭐가 됐든, 가 보면 알게 되겠지.`,JPN:`とにかく、行ってみればわかるだろう。`,ENG:`Well, I'll know soon enough.`,TWN:`無論如何，去了應該就知道了。`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};